const allTags = variables['profiles'].reduce((tags, profile) => {
    return [...tags, ...profile.tags];
  }, []);

  return [...new Set(allTags)].sort();

let result = variables['profiles'];

  // Filter by selected category if not "All"
  const currentCategory = variables['443372b9-6164-410a-b8d5-eb5e52ef25d8'] || 'All';
  if (currentCategory !== 'All') {
    result = result.filter(profile => {
      return profile.tags.includes(currentCategory);
    });
  }

  // Filter by selected tags if any are selected
  if (variables['4cd36b68-6aa8-4126-8128-f80acfb7a9a6'] && variables['4cd36b68-6aa8-4126-8128-f80acfb7a9a6'].length > 0) {
    result = result.filter(profile => {
      return variables['4cd36b68-6aa8-4126-8128-f80acfb7a9a6'].every(tag => profile.tags.includes(tag));
    });
  }

  // Apply sorting
  const sortOption = variables['4b8f2385-94a9-4a9f-b1ae-207e0d301eae'] || 'nameAsc';
  switch(sortOption) {
    case 'nameAsc':
      result = [...result].sort((a, b) => a.name.localeCompare(b.name));
      break;
    case 'nameDesc':
      result = [...result].sort((a, b) => b.name.localeCompare(a.name));
      break;
    case 'rateAsc':
      result = [...result].sort((a, b) => a.rate - b.rate);
      break;
    case 'rateDesc':
      result = [...result].sort((a, b) => b.rate - a.rate);
      break;
  }

  return result;

// Get the jobs array
  const jobs = variables['86bd4912-a74e-4e56-bc92-c4c238a6825d'] || [];

  // Get the search term and current category
  const searchTerm = (variables['8f26a369-be03-4c4e-93f1-2fbf3358d223'] || '').toLowerCase();
  const currentCategory = variables['443372b9-6164-410a-b8d5-eb5e52ef25d8'] || 'All';

  // Filter jobs based on search term and category
  return jobs.filter(job => {
    // Search filter - check if job title or company name contains search term
    const matchesSearch = !searchTerm || 
      (job.job_title && job.job_title.toLowerCase().includes(searchTerm)) || 
      (job.company_name && job.company_name.toLowerCase().includes(searchTerm)) ||
      (job.job_description && job.job_description.toLowerCase().includes(searchTerm));

    // Category filter - check if job matches selected category
    const matchesCategory = currentCategory === 'All' || 
      job.category === currentCategory;

    // Return true if job matches both search and category filters
    return matchesSearch && matchesCategory;
  });
